35	type ResultHandler<T = unknown> = {
36	  resolve: (value: T) => void
37	  reject: (error: Error) => void
38	}
39	
40	export class GeneratorProcess {
41	  private child?: ChildProcessByStdio<Writable, null, Readable>
42	  private handlers: Record<string, ResultHandler> = {}
43	  private initPromise?: Promise<void>
44	  private isNode: boolean
45	  private errorLogs = ''
46	  private pendingError: Error | undefined
47	  private exited = false
48	
49	  constructor(
50	    private pathOrCommand: string,
51	    { isNode = false }: GeneratorProcessOptions = {},
52	  ) {
53	    this.isNode = isNode
54	  }
55	
56	  async init(): Promise<void> {
57	    if (!this.initPromise) {
58	      this.initPromise = this.initSingleton()
59	    }
60	    return this.initPromise
61	  }
62	
63	  initSingleton(): Promise<void> {
64	    return new Promise((resolve, reject) => {
65	      if (this.isNode) {
66	        this.child = fork(this.pathOrCommand, [], {
67	          stdio: ['pipe', 'inherit', 'pipe', 'ipc'],
68	          env: {
69	            ...process.env,
70	            PRISMA_GENERATOR_INVOCATION: 'true',
71	          },
72	          // TODO: this assumes the host has at least 8 GB of RAM which may not be the case.
73	          execArgv: ['--max-old-space-size=8096'],
74	        }) as ChildProcessByStdio<Writable, null, Readable>
75	      } else {
76	        this.child = spawn(this.pathOrCommand, {
77	          stdio: ['pipe', 'inherit', 'pipe'],
78	          env: {
79	            ...process.env,
80	            PRISMA_GENERATOR_INVOCATION: 'true',
81	          },
82	          shell: true,
83	        })
84	      }
85	
86	      this.child.on('exit', (code, signal) => {
87	        debug(`child exited with code ${code} on signal ${signal}`)
88	        this.exited = true
89	
90	        if (code) {
91	          const error = new GeneratorError(
92	            `Generator ${JSON.stringify(this.pathOrCommand)} failed:\n\n${this.errorLogs}`,
93	          )
94	          this.pendingError = error
95	          this.rejectAllHandlers(error)
96	        }
97	      })
98	
99	      // Set the error handler for stdin to prevent unhandled error events.
100	      // We handle write errors explicitly in `sendMessage` method.
101	      this.child.stdin.on('error', () => {})
102	
103	      this.child.on('error', (error) => {
104	        debug(error)
105	        this.pendingError = error
106	
107	        // Handle startup errors: reject the `init` promise.
108	        if ((error as NodeJS.ErrnoException).code === 'EACCES') {
109	          reject(
110	            new Error(
111	              `The executable at ${this.pathOrCommand} lacks the right permissions. Please use ${bold(
112	                `chmod +x ${this.pathOrCommand}`,
113	              )}`,
114	            ),
115	          )
116	        } else {
117	          reject(error)
118	        }
119	
120	        // Reject any pending requests if the error event happened after spawning.
121	        this.rejectAllHandlers(error)
122	      })
123	
124	      const stderrInterface = readline.createInterface({
125	        input: this.child.stderr,
126	        crlfDelay: Infinity,
127	      })
128	
129	      stderrInterface.on('line', (line: string) => {
130	        let data: JsonRpc.Response | undefined
131	        try {
132	          data = JSON.parse(line)
133	        } catch (e) {
134	          this.errorLogs += line + '\n'
135	          debug(line)
136	        }
137	        if (data) {
138	          this.handleResponse(data)
139	        }
140	      })
141	
142	      this.child.on('spawn', resolve)
143	    })
144	  }
145	
146	  private rejectAllHandlers(error: Error) {
147	    for (const id of Object.keys(this.handlers)) {
148	      this.handlers[id].reject(error)
149	      delete this.handlers[id]
150	    }
151	  }
152	
153	  private handleResponse(data: JsonRpc.Response): void {
154	    if (data.jsonrpc && data.id) {
155	      if (typeof data.id !== 'number') {
156	        throw new Error(`message.id has to be a number. Found value ${data.id}`)
157	      }
158	      if (this.handlers[data.id]) {
159	        if (JsonRpc.isErrorResponse(data)) {
160	          const error = new GeneratorError(data.error.message, data.error.code, data.error.data)
161	          this.handlers[data.id].reject(error)
162	        } else {
163	          this.handlers[data.id].resolve(data.result)
164	        }
165	        delete this.handlers[data.id]
166	      }
167	    }
168	  }
169	
170	  private sendMessage(message: JsonRpc.Request, callback: (error?: Error) => void): void {
171	    if (!this.child) {
172	      callback(new GeneratorError('Generator process has not started yet'))
173	      return
174	    }
175	
176	    if (!this.child.stdin.writable) {
177	      callback(new GeneratorError('Cannot send data to the generator process, process already exited'))
178	      return
179	    }
180	
181	    this.child.stdin.write(JSON.stringify(message) + '\n', (error) => {
182	      if (!error) {
183	        return callback()
184	      }
185	
186	      if ((error as NodeJS.ErrnoException).code === 'EPIPE') {
187	        // Child process already terminated but we didn't know about it yet on Node.js side, so the `exit` event hasn't
188	        // been emitted yet, and the `child.stdin.writable` check also passed. We skip this error and let the `exit`
189	        // event handler reject active requests (including this one).
190	        return callback()
191	      }
192	
193	      callback(error)
194	    })
195	  }
196	
197	  private getMessageId(): number {
198	    return globalMessageId++
199	  }
200	
201	  stop(): void {
202	    if (this.child && !this.child?.killed) {
203	      // Before `5.10.0` we were not passing explicitly a signal (so using the default `SIGTERM` signal)
204	      // the "should work with a custom generator" test was failing very often on macOS (in CI) with a timeout for example
205	      //
206	      // See https://www.gnu.org/software/libc/manual/html_node/Termination-Signals.html
207	      // The SIGTERM signal is a generic signal used to cause program termination. Unlike SIGKILL, this signal can be blocked, handled, and ignored. It is the normal way to politely ask a program to terminate.
208	      // The SIGKILL signal is used to cause immediate program termination. It cannot be handled or ignored, and is therefore always fatal. It is also not possible to block this signal.
209	
210	      // We send SIGTERM first, and if the process is still alive after 2 seconds, we send SIGKILL
211	      this.child.kill('SIGTERM')
212	
213	      const timeoutMs = 2_000
214	      const intervalMs = 200
215	      let interval: NodeJS.Timeout | undefined
216	      let timeout: NodeJS.Timeout | undefined
217	      // eslint-disable-next-line @typescript-eslint/no-floating-promises
218	      Promise.race([
219	        new Promise<void>((resolve) => {
220	          timeout = setTimeout(resolve, timeoutMs)
221	        }),
222	        new Promise<string>((resolve) => {
223	          interval = setInterval(() => {
224	            if (this.exited) {
225	              return resolve('exited')
226	            }
227	          }, intervalMs)
228	        }),
229	      ])
230	        .then((result) => {
231	          if (result !== 'exited') {
232	            this.child?.kill('SIGKILL')
233	          }
234	        })
235	        .finally(() => {
236	          clearInterval(interval)
237	          clearTimeout(timeout)
238	        })
239	    }
240	  }
241	
242	  private rpcMethod<T, U>(method: string, mapResult: (x: unknown) => U = (x) => x as U): (arg: T) => Promise<U> {
243	    return (params: T): Promise<U> =>
244	      new Promise((resolve, reject) => {
245	        if (this.pendingError) {
246	          reject(this.pendingError)
247	          return
248	        }
249	
250	        const messageId = this.getMessageId()
251	
252	        this.handlers[messageId] = {
253	          resolve: (result) => resolve(mapResult(result)),
254	          reject,
255	        }
256	
257	        this.sendMessage(
258	          {
259	            jsonrpc: '2.0',
260	            method,
261	            params,
262	            id: messageId,
263	          },
264	          (error) => {
265	            if (error) reject(error)
266	          },
267	        )
268	      })
269	  }
270	
271	  getManifest = this.rpcMethod<GeneratorConfig, GeneratorManifest | null>(
272	    'getManifest',
273	    (result) => (result as { manifest?: GeneratorManifest | null }).manifest ?? null,
274	  )
275	
276	  generate = this.rpcMethod<GeneratorOptions, void>('generate')
277	}
