import type * as DMMF from '@prisma/dmmf'

/** Maps a DMMF field type to its TypeScript equivalent. */
export function fieldToTsType(field: DMMF.Field): string {
  if (field.kind === 'enum') return field.type
  if (field.kind === 'object') return field.type

  switch (field.type) {
    case 'BigInt':
      return 'bigint'
    case 'Boolean':
      return 'boolean'
    case 'Bytes':
      return 'Uint8Array'
    case 'DateTime':
      return 'Date'
    case 'Decimal':
      return 'number'
    case 'Float':
      return 'number'
    case 'Int':
      return 'number'
    case 'Json':
      return 'unknown'
    case 'String':
      return 'string'
    default:
      return 'unknown'
  }
}

function fieldDeclaration(field: DMMF.Field, optional: boolean): string {
  const base = fieldToTsType(field)
  const tsType = field.isList ? `${base}[]` : base
  const optMark = optional || !field.isRequired ? '?' : ''
  return `  ${field.name}${optMark}: ${tsType}`
}

/** Generates a TypeScript interface for a Prisma model, including all fields. */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields.map((f) => fieldDeclaration(f, false)).join('\n')
  return `export interface ${model.name} {\n${fields}\n}`
}

/**
 * Generates a CreateInput type for a model.
 * Relation fields are omitted; auto-generated fields (defaults, generated) are optional.
 */
export function renderCreateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue || f.isGenerated === true
      return fieldDeclaration(f, optional)
    })
    .join('\n')
  return `export type ${model.name}CreateInput = {\n${fields}\n}`
}

/** Generates an UpdateInput type for a model where every field is optional. */
export function renderUpdateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => fieldDeclaration(f, true))
    .join('\n')
  return `export type ${model.name}UpdateInput = {\n${fields}\n}`
}

/** Generates a WhereUniqueInput type containing only the model's ID and unique fields. */
export function renderWhereUniqueInput(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => f.isId || f.isUnique)
  const fields =
    uniqueFields.length > 0
      ? uniqueFields.map((f) => fieldDeclaration(f, false)).join('\n')
      : `  id: unknown`
  return `export type ${model.name}WhereUniqueInput = {\n${fields}\n}`
}

/** Generates a typed CRUD client class for a model that calls a REST API via fetch. */
export function renderModelClient(model: DMMF.Model, urlPath: string): string {
  const name = model.name
  return `export class ${name}Client {
  constructor(private readonly baseUrl: string) {}

  async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {
    const query = params ? '?' + new URLSearchParams(params as Record<string, string>).toString() : ''
    const res = await fetch(\`\${this.baseUrl}/${urlPath}\${query}\`)
    if (!res.ok) throw new Error(\`findMany ${name} failed: \${res.statusText}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const key = Object.values(where)[0]
    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${key}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`findUnique ${name} failed: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const res = await fetch(\`\${this.baseUrl}/${urlPath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`create ${name} failed: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const key = Object.values(where)[0]
    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${key}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`update ${name} failed: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const key = Object.values(where)[0]
    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${key}\`, { method: 'DELETE' })
    if (!res.ok) throw new Error(\`delete ${name} failed: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }
}
`
}

/** Generates the root RestClient class that aggregates per-model client instances. */
export function renderRootClient(models: readonly DMMF.Model[]): string {
  const props = models
    .map((m) => `  readonly ${lcFirst(m.name)}: ${m.name}Client`)
    .join('\n')
  const assignments = models
    .map((m) => `    this.${lcFirst(m.name)} = new ${m.name}Client(baseUrl)`)
    .join('\n')
  return `export class RestClient {\n${props}\n\n  constructor(baseUrl: string) {\n${assignments}\n  }\n}`
}

function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/** Renders the complete `rest-client.ts` output from a DMMF document. */
export function renderFile(dmmf: DMMF.Document): string {
  const pluralMap = new Map(dmmf.mappings.modelOperations.map((op) => [op.model, op.plural]))

  const models = dmmf.datamodel.models
  const enums = dmmf.datamodel.enums

  const parts: string[] = [
    '// This file was generated by @prisma/generator-rest-client. Do not edit manually.',
    '',
  ]

  for (const en of enums) {
    const members = en.values.map((v) => `  ${v.name} = '${v.name}'`).join(',\n')
    parts.push(`export enum ${en.name} {\n${members}\n}`, '')
  }

  for (const model of models) {
    parts.push(
      renderModelInterface(model),
      '',
      renderCreateInput(model),
      '',
      renderUpdateInput(model),
      '',
      renderWhereUniqueInput(model),
      '',
    )
  }

  for (const model of models) {
    const urlPath = pluralMap.get(model.name) ?? lcFirst(model.name) + 's'
    parts.push(renderModelClient(model, urlPath))
  }

  parts.push(renderRootClient(models))

  return parts.join('\n')
}

