import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'

import { renderFile } from './template'

/**
 * Generates `rest-client.ts` into the configured output directory.
 *
 * The output directory is read from `options.generator.output` and must be set
 * explicitly in the schema's generator block (or will fall back to the manifest's
 * `defaultOutput` value of `./generated/rest-client`).
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  if (!options.generator.output) {
    throw new Error(
      '@prisma/generator-rest-client requires an `output` path in the generator block.\n' +
        "Example: output = \"./generated/rest-client\"",
    )
  }

  const outputDir = parseEnvValue(options.generator.output)
  await fs.promises.mkdir(outputDir, { recursive: true })

  const content = renderFile(options.dmmf)
  await fs.promises.writeFile(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}

